const baseConfig = $('Config Reporte').first().json;
const triggerConfig = $('SetTrigger - Flujo').first()?.json || {};
const mergedFlags = { ...(baseConfig.flags || {}) };
function mergeFlag(name) {
  const value = triggerConfig[name];
  if (value === undefined || value === null || value === '') return;
  if (typeof value === 'boolean') mergedFlags[name] = value;
  else if (typeof value === 'number') mergedFlags[name] = value !== 0;
  else {
    const text = String(value).trim().toLowerCase();
    if (['true','1','yes','y','si','s','on','enabled'].includes(text)) mergedFlags[name] = true;
    else if (['false','0','no','n','off','disabled'].includes(text)) mergedFlags[name] = false;
  }
}
for (const key of ['include_attachment','include_detail','include_summary','include_operational_notes','include_itop_button_footer','send_email','include_requirements','include_incidents','include_changes','include_problems']) mergeFlag(key);
const config = { ...baseConfig, ...triggerConfig, flags: mergedFlags };
for (const [key, value] of Object.entries(mergedFlags)) config[key] = value;
const company = String(config.Company || config.company || 'TecnoComp').trim();
const itopOrganization = String(config.itop_organization || '').trim();


function isEnabledFlag(value, defaultValue = true) {
  if (value === undefined || value === null || value === '') return defaultValue;
  if (typeof value === 'boolean') return value;
  const normalized = String(value).trim().toLowerCase();
  return ['true', '1', 'yes', 'si', 'sí', 'y', 'on', 'enabled'].includes(normalized);
}

const includeRequirements = isEnabledFlag(config.include_requirements, true);
const includeIncidents = isEnabledFlag(config.include_incidents, true);
const includeChanges = isEnabledFlag(config.include_changes, true);
const includeProblems = isEnabledFlag(config.include_problems, true);

const enabledTicketTypes = new Set();
if (includeRequirements) enabledTicketTypes.add('requirement');
if (includeIncidents) enabledTicketTypes.add('incident');
if (includeChanges) enabledTicketTypes.add('change');
if (includeProblems) enabledTicketTypes.add('problem');

function enabledTicketTypeText() {
  const labels = [];
  if (includeRequirements) labels.push('Requerimientos');
  if (includeIncidents) labels.push('Incidentes');
  if (includeChanges) labels.push('Cambios');
  if (includeProblems) labels.push('Problemas');
  return labels.length ? labels.join(', ') : 'Sin tipos habilitados';
}


function csvEscape(value) {
  const text = String(value ?? '').replace(/"/g, '""');
  return `"${text}"`;
}

function escapeHtml(value) {
  return String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#039;');
}
function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}

function stripHtml(value) {
  return String(value ?? '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#039;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}
function rawField(obj, names) {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return undefined;
}
function entryDateValue(entry, fallbackKey = '') {
  if (!entry || typeof entry !== 'object') return fallbackKey;
  return entry.date || entry.created || entry.created_at || entry.creation_date || entry.timestamp || entry.time || fallbackKey || '';
}
function entryAuthorValue(entry) {
  if (!entry || typeof entry !== 'object') return '';
  return entry.user_id_friendlyname || entry.user_friendlyname || entry.user_name || entry.user_login || entry.author || entry.author_friendlyname || '';
}
function normalizeLogText(value, fallbackKey = '') {
  if (value === undefined || value === null || value === '') return '';

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    const text = stripHtml(value);
    return text && text !== '[object Object]' ? text : '';
  }

  if (Array.isArray(value)) {
    const normalized = value
      .map((entry, index) => ({
        date: entryDateValue(entry, String(index).padStart(6, '0')),
        text: normalizeLogText(entry, String(index).padStart(6, '0')),
      }))
      .filter(e => e.text);
    if (!normalized.length) return '';
    normalized.sort((a, b) => String(a.date).localeCompare(String(b.date)));
    return normalized[normalized.length - 1].text;
  }

  if (typeof value === 'object') {
    const direct = rawField(value, [
      'message', 'html', 'text', 'body', 'content', 'comment', 'note',
      'last_comment', 'last_note', 'entry', 'value', 'description'
    ]);

    if (direct !== undefined && direct !== value) {
      const text = normalizeLogText(direct, fallbackKey);
      if (text) {
        const date = entryDateValue(value, fallbackKey);
        const author = entryAuthorValue(value);
        const prefix = [date, author].map(v => stripHtml(v)).filter(Boolean).join(' - ');
        return prefix ? `${prefix}: ${text}` : text;
      }
    }

    const collection = value.entries || value.items || value.log || value.logs || value.records || value.data;
    if (collection && collection !== value) {
      const entries = Array.isArray(collection)
        ? collection.map((v, i) => [String(i).padStart(6, '0'), v])
        : Object.entries(collection);
      const normalized = entries
        .map(([key, entry]) => ({ date: entryDateValue(entry, key), text: normalizeLogText(entry, key) }))
        .filter(e => e.text);
      if (!normalized.length) return '';
      normalized.sort((a, b) => String(a.date).localeCompare(String(b.date)));
      return normalized[normalized.length - 1].text;
    }

    const leafTexts = [];
    const ignored = new Set(['id', 'key', 'code', 'class', 'finalclass', 'type', 'attribute', 'attcode', 'att_code']);
    for (const [key, val] of Object.entries(value)) {
      if (ignored.has(String(key).toLowerCase())) continue;
      if (typeof val === 'string' || typeof val === 'number' || typeof val === 'boolean') {
        const text = stripHtml(val);
        if (text && text !== '[object Object]') leafTexts.push(text);
      }
    }
    const unique = [...new Set(leafTexts)].filter(t => t.length > 1);
    return unique.slice(-3).join(' / ');
  }

  return '';
}
function getLastReadableNote(fields) {
  const candidates = [
    rawField(fields, ['last_comment','last_note','last_public_log','last_private_log','last_update_reason','last_change']),
    rawField(fields, ['public_log','private_log','user_satisfaction','operational_status']),
    rawField(fields, ['description'])
  ];

  for (const candidate of candidates) {
    const text = normalizeLogText(candidate);
    if (text) return text;
  }
  return '-';
}
function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}
function fmtDate(value) {
  if (!value || value === '-') return '-';
  const d = new Date(String(value).replace(' ', 'T'));
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleString('es-CL', { timeZone: config.timezone || 'America/Santiago', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
}
function fmtDateOnly(value) {
  if (!value || value === '-') return '-';
  const d = new Date(String(value).replace(' ', 'T'));
  if (Number.isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString('es-CL', { timeZone: config.timezone || 'America/Santiago', year:'numeric', month:'2-digit', day:'2-digit' });
}
function ageHours(value) {
  if (!value) return 0;
  const d = new Date(String(value).replace(' ', 'T'));
  if (Number.isNaN(d.getTime())) return 0;
  return Math.max(0, Math.floor((Date.now() - d.getTime()) / 36e5));
}
function ageTextFromHours(h) {
  const days = Math.floor(h / 24); const hours = h % 24;
  if (days > 0) return `${days}d ${hours}h`;
  return `${hours}h`;
}
function td(value, align='left') {
  return `<td align="${align}" style="font-size:12px; line-height:16px; color:#1f2937; padding:8px 7px; border-bottom:1px solid #edf2f7; vertical-align:top;">${value}</td>`;
}
function badge(text, cls='badge-gray') { return `<span class="badge ${cls}">${escapeHtml(text)}</span>`; }
function replaceAllVars(html, replacements) { for (const [k,v] of Object.entries(replacements)) html = html.replaceAll(`{{${k}}}`, String(v)); return html; }

function translateOperationalStatus(value) {
  const raw = String(value ?? '').trim();
  if (!raw || raw === '-') return '-';

  const key = raw
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[\s-]+/g, '_');

  const map = {
    ongoing: 'En curso',
    new: 'Nuevo',
    assigned: 'Asignado',
    pending: 'Pendiente',
    waiting_for_approval: 'En espera de aprobación',
    waiting_for_customer: 'En espera del solicitante',
    waiting_for_user: 'En espera del usuario',
    waiting_for_provider: 'En espera de proveedor',
    wait_for_customer: 'En espera del solicitante',
    wait_for_user: 'En espera del usuario',
    wait_for_provider: 'En espera de proveedor',
    escalated: 'Escalado',
    resolved: 'Resuelto',
    closed: 'Cerrado',
    rejected: 'Rechazado',
    cancelled: 'Cancelado',
    canceled: 'Cancelado',
    frozen: 'Congelado',
    approved: 'Aprobado',
    implemented: 'Implementado',
    monitored: 'En monitoreo',
    validated: 'Validado',
    accepted: 'Aceptado',
    completed: 'Completado',
    failed: 'Fallido'
  };

  return map[key] || raw;
}

function normalizeTicketKind(value, fields = {}) {
  const rawValues = [
    value,
    getField(fields, ['finalclass', 'class', 'class_friendlyname', 'ticket_class', 'ticket_type', 'type', 'request_type', 'request_type_friendlyname'], ''),
    getField(fields, ['ref', 'reference', 'friendlyname'], '')
  ].map(v => String(v || '').trim()).filter(Boolean);

  const raw = rawValues.join(' ').toLowerCase();

  if (raw.includes('userrequest') || raw.includes('user request') || raw.includes('request') || raw.includes('requerimiento') || raw.includes('requisito') || raw.includes('solicitud')) {
    return { key: 'requirement', label: 'Requerimiento' };
  }
  if (raw.includes('incident') || raw.includes('incidente') || raw.includes('incidencia')) {
    return { key: 'incident', label: 'Incidente' };
  }
  if (raw.includes('change') || raw.includes('cambio')) {
    return { key: 'change', label: 'Cambio' };
  }
  if (raw.includes('problem') || raw.includes('problema')) {
    return { key: 'problem', label: 'Problema' };
  }

  return { key: 'unknown', label: rawValues[0] || 'No identificado' };
}

const generatedAt = new Date().toLocaleString('es-CL', { timeZone: config.timezone || 'America/Santiago', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
const rawRows = flattenInput($input.all());

const openStatusBlacklist = String(config.closed_status_values || 'closed,resolved,rejected,cancelled,cerrado,resuelto,rechazado').toLowerCase().split(',').map(s=>s.trim()).filter(Boolean);
let tickets = rawRows.map((row) => {
  const f = row.fields || row;
  const ref = getField(f, ['ref','friendlyname','id'], '-');
  const start = getField(f, ['start_date','creation_date','created','date'], '');
  const last = getField(f, ['last_update','last_update_date','modify_date','modification_date','updated'], start);
  const priority = getField(f, ['priority_friendlyname','priority','urgency_friendlyname','urgency'], '-');
  const status = getField(f, ['operational_status_friendlyname','operational_status','status_friendlyname','status'], '-');
  const sla = getField(f, ['tto_escalation_deadline','ttr_escalation_deadline','resolution_date','tto_deadline','ttr_deadline'], '');
  const ticketKind = normalizeTicketKind(getField(f, ['finalclass','class','class_friendlyname','ticket_class','ticket_type','type'], ''), f);
  return {
    ref,
    finalclass: getField(f, ['finalclass','class'], '-'),
    ticketType: ticketKind.key,
    ticketTypeLabel: ticketKind.label,
    title: getField(f, ['title','description','friendlyname'], '-'),
    status,
    priority,
    caller: getField(f, ['caller_id_friendlyname','caller_name','user_id_friendlyname','requestor_id_friendlyname'], '-'),
    team: getField(f, ['team_id_friendlyname','team_name','assignment_team_id_friendlyname'], '-'),
    agent: getField(f, ['agent_id_friendlyname','agent_name','assignee_id_friendlyname'], ''),
    start,
    last,
    openHours: ageHours(start),
    inactiveHours: ageHours(last),
    slaDeadline: sla,
    lastNote: getLastReadableNote(f),
  };
}).filter(t => !openStatusBlacklist.some(x => String(t.status || '').toLowerCase().includes(x)))
  .filter(t => enabledTicketTypes.has(t.ticketType));
function isSlaBreached(t) { if (!t.slaDeadline) return false; const d=new Date(String(t.slaDeadline).replace(' ','T')); return !Number.isNaN(d.getTime()) && d.getTime() < Date.now(); }
function isCritical(t) { const p=String(t.priority||'').toLowerCase(); return p.includes('critical') || p.includes('crítica') || p.includes('critica') || p.includes('1') || isSlaBreached(t) || t.openHours >= 72; }
function critBadge(t, byInactive=false) {
  const h = byInactive ? t.inactiveHours : t.openHours;
  if (isSlaBreached(t) || h >= 72 || isCritical(t)) return badge('Crítico','badge-red');
  if (h >= 48) return badge('Alto','badge-orange');
  if (h >= 24) return badge('Medio','badge-yellow');
  return badge('Normal','badge-green');
}
function slaBadge(t) { return isSlaBreached(t) ? badge('Vencido','badge-red') : badge('Sin vencimiento','badge-green'); }

tickets.sort((a,b) => b.openHours - a.openHours || String(a.ref).localeCompare(String(b.ref),'es'));

function agentKey(ticket) {
  const agent = String(ticket.agent || '').trim();
  return agent || 'Sin agente';
}

function ticketTableHeader() {
  return `<thead><tr>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Crit.</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Referencia</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Título / asunto</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Solicitante</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Creación</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Últ. mod.</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Tiempo abierto</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">SLA</th>
    <th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec;">Última observación / cambio</th>
  </tr></thead>`;
}

function ticketRow(t) {
  return `<tr>`
    + td(critBadge(t))
    + td(`<strong>${escapeHtml(t.ref)}</strong>`)
    + td(escapeHtml(t.title))
    + td(escapeHtml(t.caller))
    + td(escapeHtml(fmtDate(t.start)))
    + td(escapeHtml(fmtDate(t.last)))
    + td(`<strong>${ageTextFromHours(t.openHours)}</strong>`)
    + td(slaBadge(t))
    + td(escapeHtml(normalizeLogText(t.lastNote) || '-').slice(0, 400))
    + `</tr>`;
}

function groupByAgent(list) {
  const groups = new Map();
  const sorted = [...list].sort((a,b) => b.openHours - a.openHours || String(a.ref).localeCompare(String(b.ref),'es'));

  for (const ticket of sorted) {
    const key = agentKey(ticket);
    if (!groups.has(key)) groups.set(key, []);
    groups.get(key).push(ticket);
  }

  return Array.from(groups.entries()).sort((a, b) => {
    const aOldest = a[1][0]?.openHours || 0;
    const bOldest = b[1][0]?.openHours || 0;
    return bOldest - aOldest || a[0].localeCompare(b[0], 'es');
  });
}

function renderAgentBlock(agent, list) {
  const oldest = list[0] ? ageTextFromHours(list[0].openHours) : '-';
  const slaCount = list.filter(isSlaBreached).length;
  const criticalCount = list.filter(isCritical).length;

  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:16px; border:1px solid #dbe3ec;">
    <tr>
      <td style="background-color:#f8fafc; padding:10px 12px; border-bottom:1px solid #dbe3ec;">
        <div style="font-size:14px; line-height:20px; font-weight:bold; color:#0f172a;">${escapeHtml(agent)} <span style="color:#64748b; font-weight:normal;">(${list.length} tickets)</span></div>
        <div style="font-size:12px; line-height:18px; color:#64748b; margin-top:2px;">Más antiguo: ${escapeHtml(oldest)} · Críticos: ${criticalCount} · SLA vencido: ${slaCount}</div>
      </td>
    </tr>
    <tr>
      <td>
        <div class="ticket-scroll" style="width:100%; overflow-x:auto;">
          <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" class="ticket-table" style="width:100%;">
            ${ticketTableHeader()}
            <tbody>${list.map(ticketRow).join('')}</tbody>
          </table>
        </div>
      </td>
    </tr>
  </table>`;
}

function renderTicketSection(title, description, list, color = 'gray') {
  if (!list.length) {
    return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:18px; border:1px solid #dbe3ec; background-color:#ffffff;">
      <tr><td style="padding:14px; font-size:13px; line-height:19px; color:#64748b;">${escapeHtml(title)}: sin tickets para listar.</td></tr>
    </table>`;
  }

  const grouped = groupByAgent(list).map(([agent, agentTickets]) => renderAgentBlock(agent, agentTickets)).join('');
  return `<table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom:22px;">
    <tr>
      <td style="padding:10px 12px; background-color:${color === 'red' ? '#fef2f2' : '#f8fafc'}; border:1px solid ${color === 'red' ? '#fecaca' : '#dbe3ec'};">
        <div style="font-size:15px; line-height:21px; font-weight:bold; color:${color === 'red' ? '#991b1b' : '#111827'};">${escapeHtml(title)} <span style="font-weight:normal; color:#64748b;">(${list.length})</span></div>
        <div style="font-size:12px; line-height:18px; color:#64748b; margin-top:2px;">${escapeHtml(description)}</div>
      </td>
    </tr>
    <tr><td style="padding-top:12px;">${grouped}</td></tr>
  </table>`;
}

const ticketsOver14Days = tickets.filter(t => t.openHours > (14 * 24));
const ticketsUpTo14Days = tickets.filter(t => t.openHours <= (14 * 24));
const ticketSections =
  renderTicketSection('Tickets con más de 14 días abiertos', 'Prioridad de revisión: tickets envejecidos, agrupados por agente y ordenados desde el más antiguo al más reciente.', ticketsOver14Days, 'red') +
  renderTicketSection('Tickets abiertos hasta 14 días', 'Backlog operacional vigente, agrupado por agente y ordenado desde el más antiguo al más reciente.', ticketsUpTo14Days, 'gray');


const avgHours = tickets.length ? Math.round(tickets.reduce((s,t)=>s+t.openHours,0) / tickets.length) : 0;
const oldest = tickets[0] ? `${tickets[0].ref} / ${ageTextFromHours(tickets[0].openHours)}` : '-';
const totalOpen = tickets.length;
const criticalCount = tickets.filter(isCritical).length;
const slaBreachedCount = tickets.filter(isSlaBreached).length;
const unassignedCount = tickets.filter(t => !String(t.agent || '').trim()).length;

const subjectBase = String(config.email_subject || 'Reporte ITSM - tickets abiertos por agente y antigüedad').trim();
const emailSubject = itopOrganization ? `${subjectBase} - ${itopOrganization}` : subjectBase;

const generatedAtFile = new Date()
  .toISOString()
  .replace(/[:.]/g, '-')
  .replace('T', '_')
  .slice(0, 19);

const csvHeaders = [
  'Criticidad',
  'Referencia',
  'Tipo',
  'Titulo / Asunto',
  'Solicitante',
  'Agente',
  'Creacion',
  'Ultima modificacion',
  'Tiempo abierto',
  'Horas sin modificacion',
  'SLA',
  'Ultima observacion / cambio'
];

function criticalityText(t) {
  if (isSlaBreached(t) || t.openHours >= 72 || isCritical(t)) return 'Critico';
  if (t.openHours >= 48) return 'Alto';
  if (t.openHours >= 24) return 'Medio';
  return 'Normal';
}

const csvRows = tickets.map(t => [
  criticalityText(t),
  t.ref,
  t.ticketTypeLabel,
  t.title,
  t.caller,
  agentKey(t),
  fmtDate(t.start),
  fmtDate(t.last),
  ageTextFromHours(t.openHours),
  ageTextFromHours(t.inactiveHours),
  isSlaBreached(t) ? 'Vencido' : 'Sin vencimiento',
  normalizeLogText(t.lastNote) || '-'
]);

const csvContent = '\uFEFF' + [
  csvHeaders.map(csvEscape).join(';'),
  ...csvRows.map(row => row.map(csvEscape).join(';')),
].join('\r\n');

return [{
  json: {
    flags: config.flags || {},
    include_attachment: config.flags?.include_attachment ?? config.include_attachment,
    include_detail: config.flags?.include_detail ?? config.include_detail,
    include_summary: config.flags?.include_summary ?? config.include_summary,
    include_operational_notes: config.flags?.include_operational_notes ?? config.include_operational_notes,
    include_itop_button_footer: config.flags?.include_itop_button_footer ?? config.include_itop_button_footer,
    email_from: config.email_from,
    email_to: config.email_to,
    email_cc: config.email_cc || '',
